import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"雍和门（天王殿）","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong/yonghe-men.md","filePath":"religion/yonghegong/yonghe-men.md","lastUpdated":1784720050000}'),n={name:"religion/yonghegong/yonghe-men.md"};function i(r,t,d,s,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="雍和门-天王殿" tabindex="-1">雍和门（天王殿） <a class="header-anchor" href="#雍和门-天王殿" aria-label="Permalink to &quot;雍和门（天王殿）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1529832421193-7273a0766e76?w=1200&amp;q=80" alt="雍和门殿宇"></p><blockquote><p>&quot;王府正门，伽蓝山门——一门两重身份，铜狮碑亭守其前，天王弥勒镇其中。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>雍和门是雍和宫的正门，即寺院的&quot;山门&quot;，其前身正是雍亲王府与行宫时期的王府正门。乾隆九年（1744年）改寺后，此殿依藏传佛教寺院格局辟为天王殿，殿内供奉弥勒菩萨、韦驮、四大天王与布袋和尚，门楣之上仍悬&quot;雍和宫&quot;匾额，王府正门与寺院山门的身份在此叠合。</p><p>殿前的院落同样大有看头：一对乾隆年间的铜狮蹲踞门旁，东西两座碑亭内立有御制石碑，其中西侧的乾隆《喇嘛说》碑以汉、满、蒙、藏四体文字镌刻，是研究清代民族宗教政策最重要的实物文献之一。</p><p>雍和门虽居天王殿之位，却兼有山门之实。门楣&quot;雍和宫&quot;匾额为满、汉、蒙、藏四体合璧，与寺内诸碑遥相呼应——四种文字并列，正是这座寺院&quot;汉藏一家、满蒙一体&quot;身份最直白的宣示。</p><h3 id="四大天王与-风调雨顺" tabindex="-1">四大天王与&quot;风调雨顺&quot; <a class="header-anchor" href="#四大天王与-风调雨顺" aria-label="Permalink to &quot;四大天王与&quot;风调雨顺&quot;&quot;">​</a></h3><p>殿内东西两侧的四大天王，各持法器，暗合民间&quot;风调雨顺&quot;之愿：</p><table tabindex="0"><thead><tr><th style="text-align:left;">天王</th><th style="text-align:left;">方位</th><th style="text-align:left;">法器</th><th style="text-align:left;">寓意</th></tr></thead><tbody><tr><td style="text-align:left;">东方持国天王</td><td style="text-align:left;">东</td><td style="text-align:left;">琵琶</td><td style="text-align:left;">琵琶须&quot;调&quot;，主&quot;调&quot;</td></tr><tr><td style="text-align:left;">南方增长天王</td><td style="text-align:left;">南</td><td style="text-align:left;">宝剑</td><td style="text-align:left;">剑锋锐利，&quot;锋&quot;谐&quot;风&quot;</td></tr><tr><td style="text-align:left;">西方广目天王</td><td style="text-align:left;">西</td><td style="text-align:left;">赤龙（蛇）</td><td style="text-align:left;">龙蛇顺服，主&quot;顺&quot;</td></tr><tr><td style="text-align:left;">北方多闻天王</td><td style="text-align:left;">北</td><td style="text-align:left;">宝伞</td><td style="text-align:left;">伞可遮&quot;雨&quot;，主&quot;雨&quot;</td></tr></tbody></table><p>合而为&quot;风调雨顺&quot;，寄托国泰民安、五谷丰登之愿——护世四天王守于山门之内，既是护法，也是护国。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">规格与内容</th></tr></thead><tbody><tr><td style="text-align:left;">殿宇规制</td><td style="text-align:left;">面阔五间，黄琉璃瓦歇山顶，原王府正门升格</td></tr><tr><td style="text-align:left;">正中供奉</td><td style="text-align:left;">弥勒菩萨（天冠菩萨装，藏式造型，与汉地布袋弥勒不同）</td></tr><tr><td style="text-align:left;">弥勒背后</td><td style="text-align:left;">韦驮菩萨，护法将军装束，面向大雄宝殿护持道场</td></tr><tr><td style="text-align:left;">东西两侧</td><td style="text-align:left;">四大天王（东方持国、南方增长、西方广目、北方多闻）</td></tr><tr><td style="text-align:left;">北侧</td><td style="text-align:left;">布袋和尚（大肚弥勒），笑口常开，迎纳十方来客</td></tr><tr><td style="text-align:left;">殿外铜狮</td><td style="text-align:left;">一对，乾隆年间铸，蹲踞雍和门前，彰显皇家气度</td></tr><tr><td style="text-align:left;">东碑亭</td><td style="text-align:left;">立《雍和宫碑记》（乾隆九年，1744年），记述改寺缘起</td></tr><tr><td style="text-align:left;">西碑亭</td><td style="text-align:left;">立乾隆御制《喇嘛说》碑（乾隆五十七年，1792年）</td></tr></tbody></table><h3 id="《喇嘛说》四体碑" tabindex="-1">《喇嘛说》四体碑 <a class="header-anchor" href="#《喇嘛说》四体碑" aria-label="Permalink to &quot;《喇嘛说》四体碑&quot;">​</a></h3><p>《喇嘛说》碑为方形石碑，四面分别镌刻满、汉、蒙、藏四种文字，碑文由乾隆帝亲撰，系统阐述喇嘛教（藏传佛教）源流与格鲁派兴起的缘由，并详述&quot;金瓶掣签&quot;制度的设立始末。乾隆五十七年（1792年），为革除大活佛转世被贵族家族把持的弊端，清廷颁行金瓶掣签：候选灵童之名书于象牙签上，投入金瓶，于佛前公开掣定。金瓶共制两只，一只驻藏于拉萨大昭寺，用于达赖、班禅等大活佛转世；另一只即供奉于雍和宫，用于蒙古地区大活佛转世。一碑两瓶，标志着中央政府对活佛转世事务管理的制度化。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="一门之变-府寺之迁" tabindex="-1">一门之变，府寺之迁 <a class="header-anchor" href="#一门之变-府寺之迁" aria-label="Permalink to &quot;一门之变，府寺之迁&quot;">​</a></h3><p>雍和门原是雍亲王府的正门。雍正十三年（1735年）雍正帝驾崩，灵柩经由此门出入，殿宇改覆黄瓦；1744年改寺，正门之内重塑天王，门额&quot;雍和宫&quot;三字却沿用至今。一座门楼浓缩了王府、行宫、寺院三重身份的更迭，是读懂雍和宫的第一把钥匙。</p><h3 id="铜狮与御碑的等级密码" tabindex="-1">铜狮与御碑的等级密码 <a class="header-anchor" href="#铜狮与御碑的等级密码" aria-label="Permalink to &quot;铜狮与御碑的等级密码&quot;">​</a></h3><p>寺院山门前立铜狮、设御碑亭，本是皇家寺院才有的规制。雍和门前的铜狮铸工精细，须发毕张；两座碑亭覆以黄瓦，碑首雕蟠龙——这些细节都在无声地宣示：雍和宫不是寻常寺庙，而是皇帝&quot;家庙&quot;级别的国家寺院。</p><h3 id="金瓶掣签在雍和宫" tabindex="-1">金瓶掣签在雍和宫 <a class="header-anchor" href="#金瓶掣签在雍和宫" aria-label="Permalink to &quot;金瓶掣签在雍和宫&quot;">​</a></h3><p>《喇嘛说》碑立三年之前，金瓶掣签制度已先行确立。驻京的那只金瓶，即供奉于雍和宫。清代蒙古地区大活佛（如章嘉呼图克图、哲布尊丹巴呼图克图等世系）的转世灵童认定，须在雍和宫释迦佛像前，由理藩院堂官会同掌印札萨克达喇嘛共同主持掣签：将候选灵童的名姓、生辰书于象牙签上，投入金瓶，诵经祈祷后当众掣出一签，以定转世。掣签全过程公开进行，结果奏报皇帝批准。一碑一瓶，使活佛转世这一宗教事务有章可循、有器可凭，从根本上杜绝了转世灵童被王公贵族家族操纵的积弊。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>藏式天冠弥勒</strong>：与汉地寺院常见的布袋弥勒不同，此处弥勒为头戴五佛冠的菩萨装，是藏传佛教寺院的典型特征。</li><li><strong>乾隆《喇嘛说》四体碑</strong>：汉满蒙藏四体合璧，金瓶掣签制度的原始文献，国家一级文物级别的历史见证。</li><li><strong>东碑亭《雍和宫碑记》</strong>：与《喇嘛说》碑东西对峙，记录1744年改寺始末。</li><li><strong>殿外铜狮</strong>：乾隆年间铸，是王府—皇家寺院等级的实物标识。</li><li><strong>四体合璧门额</strong>：雍和门匾额满、汉、蒙、藏四体并列，是全寺民族交融主题的缩影。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>碑亭内石碑文字细密，建议放慢脚步辨读四体文字，体会&quot;一碑四文&quot;的匠心。</li><li>殿内佛像禁止拍照，请遵守寺院规定。</li><li>四大天王手中法器各有寓意（剑、琵琶、伞、蛇），可对照上表辨认&quot;风调雨顺&quot;。</li><li>弥勒菩萨背后即是韦驮，过殿时勿忘回望。</li><li>此处为礼佛要地，请勿大声喧哗、指点佛像。</li></ul><hr><p><strong>📍 位置</strong>：雍和宫中轴线第二进院落，牌楼院以北 <strong>⏱️ 建议游览</strong>：15-20分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/religion/yonghegong/">雍和宫概览</a></p><p><strong>⬅️ 上一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/pailou-yuan.html">牌楼院与昭泰门</a> ｜ <strong>➡️ 下一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/yonghe-dadian.html">雍和宫殿（大雄宝殿）</a></p>',29)])])}const f=e(n,[["render",i]]);export{q as __pageData,f as default};
